namespace sv_90fd1cff063b4e1fa682d676176e3799.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    ];

    private static readonly Dictionary<string, List<string>> DoctorSlots = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Williams"] = ["9:30 AM", "10:00 AM", "11:30 AM", "2:30 PM"],
        ["Dr. Patel"] = ["8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM"]
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        if (DoctorSlots.TryGetValue(doctor, out var slots))
        {
            return Task.FromResult(new List<string>(slots));
        }

        return Task.FromResult(new List<string>());
    }

    /// <summary>
    /// Validates patient data against server-side business rules.
    /// Returns a dictionary of field name → error messages.
    /// </summary>
    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Reject email with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(AppointmentModel.Email)] = ["Account has outstanding balance"];
        }

        // Reject "None" insurance with Dr. Smith (doesn't accept self-pay)
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(AppointmentModel.Doctor)] =
                ["Selected doctor does not accept self-pay patients"];
        }

        // Reject 10:00 AM slot as taken (simulates race condition)
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(AppointmentModel.TimeSlot)] = ["This slot is no longer available"];
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_90fd1cff063b4e1fa682d676176e3799.Services;

public class AppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Appointment date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason for visit cannot exceed 500 characters.")]
    public string? ReasonForVisit { get; set; }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_90fd1cff063b4e1fa682d676176e3799.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_90fd1cff063b4e1fa682d676176e3799.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

<EditForm EditContext="editContext" OnSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="model.PatientName" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-control" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-control"
                             @bind-Value="model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Appointment Date</label>
                <InputDate id="date" class="form-control"
                           @bind-Value="model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeslot">Time Slot</label>
                <InputSelect id="timeslot" class="form-control" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3"
                               @bind-Value="model.ReasonForVisit" />
                <ValidationMessage For="() => model.ReasonForVisit" />
                @if (model.ReasonForVisit is not null)
                {
                    <small class="text-muted">@model.ReasonForVisit.Length / 500</small>
                }
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Checking Availability..." : "Check Availability")
            </button>
        </fieldset>
    }
</EditForm>

@if (confirmationMessage is not null)
{
    <div class="alert alert-success mt-3">@confirmationMessage</div>
}

@code {
    private AppointmentModel model = new();
    private EditContext editContext = null!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private string? confirmationMessage;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    // Fields that belong to step 1, used for partial validation.
    private static readonly string[] Step1Fields =
        [nameof(AppointmentModel.PatientName), nameof(AppointmentModel.Email),
         nameof(AppointmentModel.Phone), nameof(AppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step-1 fields.
        editContext.Validate();

        var hasStep1Errors = Step1Fields.Any(f =>
            editContext.GetValidationMessages(editContext.Field(f)).Any());

        if (!hasStep1Errors)
        {
            showStep2 = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        confirmationMessage = null;
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService
                .GetAvailableSlotsAsync(model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
        }
    }

    private async Task HandleSubmit()
    {
        confirmationMessage = null;

        // Full form validation (annotations).
        if (!editContext.Validate())
        {
            return;
        }

        // Future-date check
        if (model.AppointmentDate.HasValue &&
            model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            customValidator!.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(AppointmentModel.AppointmentDate)] =
                    ["Appointment date must be in the future."]
            });
            return;
        }

        isSubmitting = true;

        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email!,
                model.InsuranceProvider!,
                model.Doctor!,
                model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            confirmationMessage =
                $"Appointment booked with {model.Doctor} on " +
                $"{model.AppointmentDate:MMM dd, yyyy} at {model.TimeSlot}.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

